import '@ds-mo/ui/dist/components/ds-tab-group.js';

files.content:
:host {
  display: block;
}

.tab-list {
  display: flex;
  align-items: center;
  position: relative;
  border-bottom: var(--dimension-stroke-width-015) solid var(--color-border-secondary);
}

.tab {
  display: flex;
  align-items: center;
  justify-content: center;
  padding: var(--dimension-space-075);
  background-color: transparent;
  border: none;
  border-radius: var(--dimension-radius-075);
  cursor: pointer;
  -webkit-user-select: none;
  user-select: none;
  color: var(--color-foreground-secondary);
  position: relative;
  transition: color var(--effect-motion-short-2), background-color var(--effect-motion-short-2);
  flex-shrink: 0;
  height: var(--dimension-size-400);
  box-sizing: border-box;
  --_hover-bg: var(--color-interaction-hover);
  --_pressed-bg: var(--color-interaction-pressed);
}

.tab:hover { background-color: var(--_hover-bg); }
.tab:active { background-color: var(--_pressed-bg); }

.tab--selected { color: var(--color-foreground-primary); }

.tab:focus-visible {
  outline: var(--dimension-stroke-width-025) solid var(--color-interaction-focus);
  outline-offset: var(--dimension-space-025);
}

.tab:disabled,
.tab[aria-disabled="true"] {
  opacity: 0.5;
  cursor: not-allowed;
  pointer-events: none;
}

/* Background context */
.on-medium {
  --_hover-bg: var(--color-interaction-on-medium-background-hover);
  --_pressed-bg: var(--color-interaction-on-medium-background-pressed);
}

.on-bold {
  --_hover-bg: var(--color-interaction-on-bold-background-hover);
  --_pressed-bg: var(--color-interaction-on-bold-background-pressed);
  color: var(--color-foreground-on-bold-background-secondary);
}

.on-bold.tab--selected { color: var(--color-foreground-on-bold-background-primary); }

.on-strong {
  --_hover-bg: var(--color-interaction-on-strong-background-hover);
  --_pressed-bg: var(--color-interaction-on-strong-background-pressed);
  color: var(--color-foreground-on-bold-background-secondary);
}

.on-strong.tab--selected { color: var(--color-foreground-on-bold-background-primary); }

.on-always-dark {
  --_hover-bg: var(--color-always-dark-interaction-hover);
  --_pressed-bg: var(--color-always-dark-interaction-pressed);
  color: var(--color-always-dark-foreground-secondary);
}

.on-always-dark.tab--selected { color: var(--color-always-dark-foreground-primary); }

/* Sliding indicator */
.indicator {
  position: absolute;
  bottom: 0;
  height: 2px;
  background-color: var(--color-foreground-brand);
  border-radius: var(--dimension-radius-full, 9999px);
  transition: left var(--effect-motion-short-3), width var(--effect-motion-short-3);
  pointer-events: none;
}

import { Component, Prop, State, Event, EventEmitter, Element, Listen, Watch, h, Host } from '@stencil/core';

export type TabBackground = 'faint' | 'medium' | 'bold' | 'strong' | 'always-dark';

export interface TabItem {
  id: string;
  label: string;
  disabled?: boolean;
}

@Component({
  tag: 'ds-tab-group',
  styleUrl: 'TabGroup.css',
  scoped: true,
})
export class TabGroup {
  @Element() el!: HTMLElement;

  @Prop({ mutable: true }) value: string = '';
  @Prop() tabs: TabItem[] = [];
  @Prop() background: TabBackground | undefined;
  @Prop({ attribute: 'aria-label' }) ariaLabel: string | undefined;
  @Prop({ attribute: 'aria-labelledby' }) ariaLabelledby: string | undefined;

  @State() private indicatorLeft: number = 0;
  @State() private indicatorWidth: number = 0;

  @Event() dsChange!: EventEmitter<string>;

  private resizeObserver: ResizeObserver | null = null;

  componentDidLoad() {
    this.resizeObserver = new ResizeObserver(() => this.updateIndicator());
    const list = this.el.querySelector('[role="tablist"]') as HTMLElement;
    if (list) this.resizeObserver.observe(list);
    this.updateIndicator();
  }

  disconnectedCallback() {
    this.resizeObserver?.disconnect();
  }

  @Watch('value')
  onValueChange() {
    this.updateIndicator();
  }

  @Watch('tabs')
  onTabsChange() {
    // Allow a render cycle before measuring
    requestAnimationFrame(() => this.updateIndicator());
  }

  private updateIndicator() {
    const selected = this.el.querySelector(`[data-tab-id="${this.value}"]`) as HTMLElement | null;
    if (!selected) return;
    const list = selected.closest('.tab-list') as HTMLElement | null;
    if (!list) return;
    const listRect = list.getBoundingClientRect();
    const tabRect = selected.getBoundingClientRect();
    this.indicatorLeft = tabRect.left - listRect.left;
    this.indicatorWidth = tabRect.width;
  }

  private selectTab(id: string) {
    this.value = id;
    this.dsChange.emit(id);
  }

  @Listen('keydown')
  handleKeyDown(e: KeyboardEvent) {
    const active = this.tabs.filter(t => !t.disabled);
    if (!active.length) return;

    const currentIdx = active.findIndex(t => t.id === this.value);

    let nextIdx: number | null = null;
    if (e.key === 'ArrowRight') {
      nextIdx = (currentIdx + 1) % active.length;
    } else if (e.key === 'ArrowLeft') {
      nextIdx = (currentIdx - 1 + active.length) % active.length;
    } else if (e.key === 'Home') {
      nextIdx = 0;
    } else if (e.key === 'End') {
      nextIdx = active.length - 1;
    }

    if (nextIdx !== null) {
      e.preventDefault();
      const next = active[nextIdx];
      this.selectTab(next.id);
      const btn = this.el.querySelector(`[data-tab-id="${next.id}"]`) as HTMLElement | null;
      btn?.focus();
    }
  }

  private getBgClass(): string {
    if (!this.background || this.background === 'faint') return '';
    if (this.background === 'always-dark') return 'on-always-dark';
    return `on-${this.background}`;
  }

  render() {
    const bgClass = this.getBgClass();

    return (
      <Host class="tab-group-host">
        <div
          role="tablist"
          class="tab-list"
          aria-label={this.ariaLabel}
          aria-labelledby={this.ariaLabelledby}
        >
          {this.tabs.map(tab => {
            const isSelected = tab.id === this.value;
            return (
              <button
                key={tab.id}
                type="button"
                role="tab"
                data-tab-id={tab.id}
                class={{
                  tab: true,
                  'tab--selected': isSelected,
                  [bgClass]: !!bgClass,
                }}
                aria-selected={isSelected}
                aria-disabled={tab.disabled || undefined}
                disabled={tab.disabled}
                tabIndex={isSelected ? 0 : -1}
                onClick={() => !tab.disabled && this.selectTab(tab.id)}
              >
                <span class={isSelected ? 'text-body-medium-emphasis' : 'text-body-medium'}>
                  {tab.label}
                </span>
              </button>
            );
          })}
          <div
            class="indicator"
            style={{ left: `${this.indicatorLeft}px`, width: `${this.indicatorWidth}px` }}
          />
        </div>
      </Host>
    );
  }
}
